class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount
        print(f'Deposited {amount}. Balance: {self.balance}')

    def withdraw(self, amount):
        if amount > self.balance:
            print('Insufficient funds!')
        else:
            self.balance -= amount

    def __str__(self):
        return f'Account({self.owner}: ${self.balance})'

acc = BankAccount('Neo', 100)
acc.deposit(50)     # Deposited 50. Balance: 150
print(acc)          # Account(Neo: $150)  ← calls __str__

class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        print(f'{self.name} makes a sound')

class Dog(Animal):  # Dog inherits from Animal
    def speak(self):  # OVERRIDE parent method
        print(f'{self.name} says Woof!')

class Cat(Animal):
    def speak(self):
        print(f'{self.name} says Meow!')

d = Dog('Rex')
c = Cat('Luna')
d.speak()   # Rex says Woof!
c.speak()   # Luna says Meow!

class Vehicle:
    def __init__(self, brand, speed):
        self.brand = brand
        self.speed = speed

class Car(Vehicle):
    def __init__(self, brand, speed, doors):
        super().__init__(brand, speed)  # parent init
        self.doors = doors              # child extra

c = Car('Toyota', 120, 4)
print(c.brand, c.speed, c.doors)  # Toyota 120 4

